33	// LoadData reads and parses a template data file. The format is derived
34	// from the file extension: .json/.jsonc, .yaml/.yml, or .toml.
35	func LoadData(path string) (*Data, error) {
36		raw, err := os.ReadFile(path)
37		if err != nil {
38			return nil, fmt.Errorf("failed to read data file: %w", err)
39		}
40	
41		ext := strings.TrimPrefix(strings.ToLower(filepath.Ext(path)), ".")
42	
43		var root map[string]json.RawMessage
44	
45		switch ext {
46		case JSON, JSONC:
47			raw = []byte(jsonutil.StripComments(string(raw)))
48	
49			if err := json.Unmarshal(raw, &root); err != nil {
50				return nil, fmt.Errorf("failed to parse data file: %w", err)
51			}
52		case YAML, YML:
53			var generic map[string]any
54	
55			if err := yaml.Unmarshal(raw, &generic); err != nil {
56				return nil, fmt.Errorf("failed to parse data file: %w", err)
57			}
58	
59			if root, err = normalize(generic); err != nil {
60				return nil, fmt.Errorf("failed to parse data file: %w", err)
61			}
62		case TOML, TML:
63			var generic map[string]any
64	
65			if err := toml.Unmarshal(raw, &generic); err != nil {
66				return nil, fmt.Errorf("failed to parse data file: %w", err)
67			}
68	
69			if root, err = normalize(generic); err != nil {
70				return nil, fmt.Errorf("failed to parse data file: %w", err)
71			}
72		default:
73			return nil, fmt.Errorf("unsupported data file extension: %s", ext)
74		}
75	
76		data := &Data{}
77	
78		if env, OK := root["env"]; OK {
79			data.Env = env
80		}
81	
82		if segmentsRaw, OK := root["segments"]; OK {
83			var segments map[string]json.RawMessage
