95	// normalize re-marshals a generically decoded section (as produced by the
96	// YAML/TOML unmarshalers) to a map of raw JSON so the rest of the pipeline
97	// can treat all formats uniformly.
98	func normalize(generic map[string]any) (map[string]json.RawMessage, error) {
99		root := make(map[string]json.RawMessage, len(generic))
100	
101		for key, value := range generic {
102			b, err := json.Marshal(sanitize(value))
103			if err != nil {
104				return nil, err
105			}
106	
107			root[key] = b
108		}
109	
110		return root, nil
111	}
