113	// sanitize recursively converts map[any]any (which the YAML/TOML decoders
114	// may produce for nested maps) into map[string]any so encoding/json can
115	// marshal it.
116	func sanitize(value any) any {
117		switch v := value.(type) {
118		case map[any]any:
119			m := make(map[string]any, len(v))
120			for key, val := range v {
121				m[fmt.Sprintf("%v", key)] = sanitize(val)
122			}
123	
124			return m
125		case map[string]any:
126			m := make(map[string]any, len(v))
127			for key, val := range v {
128				m[key] = sanitize(val)
129			}
130	
131			return m
132		case []any:
133			s := make([]any, len(v))
134			for i, val := range v {
135				s[i] = sanitize(val)
136			}
137	
138			return s
139		default:
140			return v
141		}
142	}
